return [{
  json: {
    id: 'smoke-message-20260310',
    threadId: 'smoke-thread-20260310',
    internalDate: '2026-02-18T18:30:00.000Z',
    subject: 'Re: YouTube Intelligence smoke test',
    snippet: 'Please create a backlog task to review this browser automation workflow and send me a short summary.',
    text: 'Please create a backlog task to review this browser automation workflow and send me a short summary.',
    from: {
      value: [
        {
          address: 'thedavidmurray@gmail.com',
          name: 'David James Murray'
        }
      ]
    }
  }
}];

// Extract the date from the email to find the matching newsletter
const emailDate = new Date($input.item.json.internalDate);
const year = emailDate.getFullYear();
const month = String(emailDate.getMonth() + 1).padStart(2, '0');
const day = String(emailDate.getDate()).padStart(2, '0');

// Try to find the newsletter archive file
// Format: YYYY-MM-DD-evening.md
const fs = require('fs');
const path = '/data/claude-vault/13-Reports/YouTube-Newsletter';

let newsletterContent = '';
let foundFile = '';

// Look for newsletter files from the past 3 days
for (let daysBack = 0; daysBack <= 3; daysBack++) {
  const checkDate = new Date(emailDate);
  checkDate.setDate(checkDate.getDate() - daysBack);
  const checkYear = checkDate.getFullYear();
  const checkMonth = String(checkDate.getMonth() + 1).padStart(2, '0');
  const checkDay = String(checkDate.getDate()).padStart(2, '0');

  const eveningFile = `${path}/${checkYear}-${checkMonth}-${checkDay}-evening.md`;
  const morningFile = `${path}/${checkYear}-${checkMonth}-${checkDay}-morning.md`;

  try {
    if (fs.existsSync(eveningFile)) {
      newsletterContent = fs.readFileSync(eveningFile, 'utf8');
      foundFile = eveningFile;
      break;
    } else if (fs.existsSync(morningFile)) {
      newsletterContent = fs.readFileSync(morningFile, 'utf8');
      foundFile = morningFile;
      break;
    }
  } catch (e) {
    // Continue searching
  }
}

// Extract key info from the email
const userReply = $input.item.json.text || $input.item.json.snippet || '';
const userEmail = $input.item.json.from.value[0].address;
const userName = $input.item.json.from.value[0].name || userEmail.split('@')[0];
const subject = $input.item.json.subject;
const threadId = $input.item.json.threadId;
const messageId = $input.item.json.id;

return {
  json: {
    userReply,
    userEmail,
    userName,
    subject,
    threadId,
    messageId,
    newsletterContent: newsletterContent.substring(0, 8000),
    foundFile,
    originalEmail: $input.item.json
  }
};

return {
  json: {
    ...$input.item.json,
    output: `Thanks for the note. I reviewed the browser automation workflow and will summarize the CLI-first path for you shortly.\n\nACTION: Create a backlog task to review the browser automation workflow and send a short summary.\n\n- David`
  }
};

// Detect and queue internal ACTION metadata, then strip it from the outgoing email.
const output = $input.item.json.output || '';
const actionMatch = output.match(/^ACTION:\s*(.+)$/im);
const cleanOutput = output
  .replace(/^ACTION:\s*.+$/gim, '')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

let queuedAction = null;
if (actionMatch) {
  const fs = require('fs');
  queuedAction = actionMatch[1].trim();
  const action = {
    type: 'newsletter-reply',
    action: queuedAction,
    from: $input.item.json.userEmail || $('Load Newsletter Context').item.json.userEmail || 'unknown',
    subject: $('Load Newsletter Context').item.json.subject || '',
    threadId: $('Load Newsletter Context').item.json.threadId || '',
    timestamp: new Date().toISOString()
  };

  try {
    fs.appendFileSync('/data/action-queue/actions.jsonl', JSON.stringify(action) + '\n');
  } catch (e) {
    // Queue dir may not exist yet
  }
}

return {
  json: {
    ...$input.item.json,
    output: cleanOutput,
    hasAction: queuedAction !== null,
    queuedAction
  }
};

return {
  json: {
    output: $input.item.json.output,
    hasAction: $input.item.json.hasAction,
    queuedAction: $input.item.json.queuedAction,
    foundFile: $('Load Newsletter Context').item.json.foundFile,
    userEmail: $('Load Newsletter Context').item.json.userEmail,
    subject: $('Load Newsletter Context').item.json.subject
  }
};
